#include <stdio.h>
#include <inttypes.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        unsigned long long n1, n2, m;
        scanf("%llu %llu %llu", &n1, &n2, &m);
        unsigned __int128 mm = m;
        unsigned __int128 total = mm * (mm + 1) / 2; // sum 1..m
        unsigned long long diff = n1 < n2 ? n1 : n2;
        unsigned __int128 S = total < diff ? total : diff;
        unsigned __int128 ans = (unsigned __int128)n1 + n2 - 2 * S;
        unsigned long long out = (unsigned long long)ans; // fits in 64‑bit
        printf("%llu\n", out);
    }
    return 0;
}

